module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const palette = ['#ef4444', '#f97316', '#eab308', '#22c55e', '#3b82f6', '#8b5cf6', '#6b7280'];
const tiers = sections.map((s) => (s || '').trim()).filter(Boolean).map((s) => {
  const nl = s.indexOf('\n');
  return { name: nl >= 0 ? s.slice(0, nl).trim() : s.trim(), body: nl >= 0 ? s.slice(nl + 1).trim() : '' };
});
let html = `\n\n<div class="mdp-mod-tierlist">`;
tiers.forEach((t, i) => {
  const c = args.color || palette[Math.min(i, palette.length - 1)];
  html += `<div class="mdp-tl-row"><div class="mdp-tl-label" style="--tl-c:${c};">${esc(t.name)}</div>` +
    `<div class="mdp-tl-items">\n\n${t.body}\n\n</div></div>`;
});
html += `</div>\n\n`;
return html;
